test-code.code:
fun bad(src: IntArray, dst: IntArray) {
    for (i in src.indices) {
        dst[i] = src[i]
    }
}

fun bad(src: IntArray, dst: IntArray, n: Int) {
    for (i in 0 until n) {
        dst[i] = src[i]
    }
}

fun good(src: IntArray, dst: IntArray) {
    src.copyInto(dst)
}

fun good(src: IntArray, dst: IntArray, flags: BooleanArray) {
    for (i in src.indices) {
        dst[i] = src[i]
        flags[i] = true
    }
}

fun bad(src: IntArray, dst: IntArray) {
    for (i in src.indices) {
        dst[i] = src[i] * 2
    }
}

fun bad(matrix: Array<IntArray>, dst: Array<IntArray>) {
    for (i in matrix.indices) {
        for (j in matrix[i].indices) {
            dst[i][j] = matrix[i][j]
        }
    }
}

fun decode(input: CharArray, output: ByteArray) {
    val len = input.size
    for (i in 0 until len step 2) {
        output[i / 2] = ((Character.digit(input[i], 16) shl 4) +
                Character.digit(input[i + 1], 16)).toByte()
    }
}
